     1→/**
     2→ * ResponseCapture.ts - Response Capture Handler
     3→ *
     4→ * PURPOSE:
     5→ * Captures completed responses and updates task status.
     6→ * Also handles learning capture for significant insights and sends notifications.
     7→ * Extracts and persists ISC (Ideal State Criteria) to current task's ISC.json.
     8→ *
     9→ * STRUCTURE:
    10→ * Session: WORK/{session_dir}/
    11→ * Task: WORK/{session_dir}/tasks/{current_task}/
    12→ *   - ISC.json (task's criteria)
    13→ *   - THREAD.md (task's algorithm log with frontmatter metadata)
    14→ */
    15→
    16→import { readFileSync, writeFileSync, mkdirSync, existsSync } from 'fs';
    17→import { join } from 'path';
    18→import { getPaiDir } from '../lib/paths';
    19→import { sendEventToObservability, getCurrentTimestamp, getSourceApp } from '../lib/observability';
    20→import { notifyTaskComplete, notifyError, getSessionDurationMinutes } from '../lib/notifications';
    21→import { getLearningCategory, isLearningCapture } from '../lib/learning-utils';
    22→import { getPSTTimestamp, getPSTDate, getYearMonth, getISOTimestamp } from '../lib/time';
    23→import type { ParsedTranscript, StructuredResponse } from '../../skills/PAI/Tools/TranscriptParser';
    24→
    25→const BASE_DIR = getPaiDir();
    26→const WORK_DIR = join(BASE_DIR, 'MEMORY', 'WORK');
    27→const STATE_DIR = join(BASE_DIR, 'MEMORY', 'STATE');
    28→const CURRENT_WORK_FILE = join(STATE_DIR, 'current-work.json');
    29→
    30→// ============================================================================
    31→// Types
    32→// ============================================================================
    33→
    34→interface CurrentWork {
    35→  session_id: string;
    36→  session_dir: string;
    37→  current_task: string;
    38→  task_count: number;
    39→  created_at: string;
    40→}
    41→
    42→interface HookInput {
    43→  session_id: string;
    44→  transcript_path: string;
    45→  hook_event_name: string;
    46→}
    47→
    48→type EffortLevel = 'QUICK' | 'STANDARD' | 'THOROUGH' | 'TRIVIAL';
    49→
    50→interface ISCDocument {
    51→  taskId: string;
    52→  status: string;
    53→  effortLevel: string;
    54→  criteria: string[];
    55→  antiCriteria: string[];
    56→  satisfaction: {
    57→    satisfied: number;
    58→    partial: number;
    59→    failed: number;
    60→    total: number;
    61→  } | null;
    62→  createdAt: string;
    63→  updatedAt: string;
    64→}
    65→
    66→// ============================================================================
    67→// ISC Extraction Helpers
    68→// ============================================================================
    69→
    70→function extractEffortLevel(text: string): EffortLevel | null {
    71→  const match = text.match(/level\s+(QUICK|STANDARD|THOROUGH|TRIVIAL)/i);
    72→  return match ? (match[1].toUpperCase() as EffortLevel) : null;
    73→}
    74→
    75→function extractISCSatisfaction(text: string): ISCDocument['satisfaction'] | null {
    76→  // Match patterns like "6 ISC criteria, all satisfied"
    77→  const allSatisfied = text.match(/(\d+)\s*(?:ISC\s*)?criteria?,?\s*all\s*satisfied/i);
    78→  if (allSatisfied) {
    79→    const total = parseInt(allSatisfied[1], 10);
    80→    return { satisfied: total, partial: 0, failed: 0, total };
    81→  }
    82→
    83→  // Match: X/Y criteria satisfied
    84→  const partial = text.match(/(\d+)\/(\d+)\s*criteria\s*satisfied/i);
    85→  if (partial) {
    86→    return {
    87→      satisfied: parseInt(partial[1], 10),
    88→      total: parseInt(partial[2], 10),
    89→      partial: 0,
    90→      failed: 0,
    91→    };
    92→  }
    93→
    94→  return null;
    95→}
    96→
    97→// ============================================================================
    98→// Task ISC Update
    99→// ============================================================================
   100→
   101→/**
   102→ * Update task's ISC.json with extracted satisfaction data
   103→ */
   104→function updateTaskISC(sessionDir: string, currentTask: string, text: string): void {
   105→  const taskPath = join(WORK_DIR, sessionDir, 'tasks', currentTask);
   106→  const iscPath = join(taskPath, 'ISC.json');
   107→
   108→  if (!existsSync(iscPath)) {
   109→    console.error(`[ISC] Task ISC.json not found: ${iscPath}`);
   110→    return;
   111→  }
   112→
   113→  try {
   114→    const doc: ISCDocument = JSON.parse(readFileSync(iscPath, 'utf-8'));
   115→    const timestamp = getISOTimestamp();
   116→
   117→    // Extract effort level if found
   118→    const effort = extractEffortLevel(text);
   119→    if (effort) {
   120→      doc.effortLevel = effort;
   121→    }
   122→
   123→    // Extract satisfaction from response
   124→    const satisfaction = extractISCSatisfaction(text);
   125→    if (satisfaction) {
   126→      doc.satisfaction = satisfaction;
   127→      doc.status = satisfaction.satisfied === satisfaction.total ? 'COMPLETE' : 'PARTIAL';
   128→    }
   129→
   130→    // Check for completion marker
   131→    if (text.includes('✓ COMPLETE')) {
   132→      doc.status = 'COMPLETE';
   133→    }
   134→
   135→    doc.updatedAt = timestamp;
   136→
   137→    writeFileSync(iscPath, JSON.stringify(doc, null, 2), 'utf-8');
   138→    console.error(`[ISC] Updated task ISC: ${currentTask}`);
   139→  } catch (err) {
   140→    console.error(`[ISC] Error updating task ISC: ${err}`);
   141→  }
   142→}
   143→
   144→/**
   145→ * Update task THREAD.md frontmatter status
   146→ */
   147→function updateTaskMeta(sessionDir: string, currentTask: string, structured: StructuredResponse): void {
   148→  const taskPath = join(WORK_DIR, sessionDir, 'tasks', currentTask);
   149→  const threadPath = join(taskPath, 'THREAD.md');
   150→
   151→  if (!existsSync(threadPath)) {
   152→    console.error(`[Capture] Task THREAD.md not found: ${threadPath}`);
   153→    return;
   154→  }
   155→
   156→  try {
   157→    let content = readFileSync(threadPath, 'utf-8');
   158→    const timestamp = getISOTimestamp();
   159→
   160→    // Update status if complete
   161→    if (structured.completed || structured.summary) {
   162→      content = content.replace(/^status: "IN_PROGRESS"$/m, 'status: "DONE"');
   163→
   164→      // Add completedAt if not present in frontmatter
   165→      if (!content.includes('completedAt:')) {
   166→        content = content.replace(/^(---\n[\s\S]*?)(---)/, `$1completedAt: "${timestamp}"\n$2`);
   167→      }
   168→
   169→      // Add summary if not present in frontmatter
   170→      const summary = (structured.completed || structured.summary || '').substring(0, 200);
   171→      if (summary && !content.includes('summary:')) {
   172→        content = content.replace(/^(---\n[\s\S]*?)(---)/, `$1summary: "${summary.replace(/"/g, '\\"')}"\n$2`);
   173→      }
   174→    }
   175→
   176→    writeFileSync(threadPath, content, 'utf-8');
   177→    console.error(`[Capture] Updated task THREAD: ${currentTask}`);
   178→  } catch (err) {
   179→    console.error(`[Capture] Error updating task META: ${err}`);
   180→  }
   181→}
   182→
   183→// ============================================================================
   184→// Learning Capture
   185→// ============================================================================
   186→
   187→function generateFilename(description: string, type: 'LEARNING' | 'WORK'): string {
   188→  const pstTimestamp = getPSTTimestamp();
   189→  const date = pstTimestamp.slice(0, 10);
   190→  const time = pstTimestamp.slice(11, 19).replace(/:/g, '');
   191→
   192→  const cleanDesc = description
   193→    .toLowerCase()
   194→    .replace(/[^a-z0-9\s-]/g, '')
   195→    .replace(/\s+/g, '-')
   196→    .slice(0, 60);
   197→
   198→  return `${date}-${time}_${type}_${cleanDesc}.md`;
   199→}
   200→
   201→function generateLearningContent(structured: StructuredResponse, fullText: string, timestamp: string): string {
   202→  return `---
   203→capture_type: LEARNING
   204→timestamp: ${timestamp}
   205→auto_captured: true
   206→tags: [auto-capture]
   207→---
   208→
   209→# Quick Learning: ${structured.completed || structured.summary || 'Task Completion'}
   210→
   211→**Date:** ${structured.date || getPSTDate()}
   212→**Auto-captured:** Yes
   213→
   214→---
   215→
   216→## Summary
   217→
   218→${structured.summary || 'N/A'}
   219→
   220→## Analysis
   221→
   222→${structured.analysis || 'N/A'}
   223→
   224→## Actions Taken
   225→
   226→${structured.actions || 'N/A'}
   227→
   228→## Results
   229→
   230→${structured.results || 'N/A'}
   231→
   232→## Current Status
   233→
   234→${structured.status || 'N/A'}
   235→
   236→## Next Steps
   237→
   238→${structured.next || 'N/A'}
   239→
   240→---
   241→
   242→<details>
   243→<summary>Full Response</summary>
   244→
   245→${fullText.replace(/<system-reminder>[\s\S]*?<\/system-reminder>/g, '')}
   246→
   247→</details>
   248→`;
   249→}
   250→
   251→// ============================================================================
   252→// Main Capture Logic
   253→// ============================================================================
   254→
   255→function readCurrentWork(): CurrentWork | null {
   256→  try {
   257→    if (!existsSync(CURRENT_WORK_FILE)) return null;
   258→    return JSON.parse(readFileSync(CURRENT_WORK_FILE, 'utf-8'));
   259→  } catch {
   260→    return null;
   261→  }
   262→}
   263→
   264→async function captureWorkSummary(text: string, structured: StructuredResponse): Promise<void> {
   265→  try {
   266→    const currentWork = readCurrentWork();
   267→
   268→    if (currentWork?.session_dir && currentWork?.current_task) {
   269→      // Update task ISC with satisfaction data
   270→      updateTaskISC(currentWork.session_dir, currentWork.current_task, text);
   271→
   272→      // Update task META if we have completion info
   273→      if (structured.summary || structured.completed) {
   274→        updateTaskMeta(currentWork.session_dir, currentWork.current_task, structured);
   275→      }
   276→    }
   277→
   278→    // Learning capture (unchanged)
   279→    const isLearning = isLearningCapture(text, structured.summary, structured.analysis);
   280→
   281→    if (isLearning) {
   282→      let description = (structured.completed || structured.summary || 'task-completion')
   283→        .replace(/^Completed\s+/i, '')
   284→        .replace(/\[AGENT:\w+\]\s*/gi, '')
   285→        .replace(/\[.*?\]/g, '')
   286→        .trim();
   287→
   288→      if (!description || description.length < 3) {
   289→        description = structured.summary || structured.analysis || 'task-completion';
   290→        description = description.replace(/^Completed\s+/i, '').trim();
   291→      }
   292→
   293→      if (!description || description.length < 3) {
   294→        description = 'general-task';
   295→      }
   296→
   297→      const yearMonth = getYearMonth();
   298→      const filename = generateFilename(description, 'LEARNING');
   299→      const category = getLearningCategory(text);
   300→      const targetDir = join(BASE_DIR, 'MEMORY', 'LEARNING', category, yearMonth);
   301→
   302→      if (!existsSync(targetDir)) {
   303→        mkdirSync(targetDir, { recursive: true });
   304→      }
   305→
   306→      const filePath = join(targetDir, filename);
   307→      const timestamp = getPSTTimestamp();
   308→      const content = generateLearningContent(structured, text, timestamp);
   309→
   310→      writeFileSync(filePath, content, 'utf-8');
   311→      console.log(`✅ Captured learning to: ${filePath}`);
   312→    }
   313→  } catch (error) {
   314→    console.error('[Capture] Error capturing work summary:', error);
   315→  }
   316→}
   317→
   318→/**
   319→ * Handle response capture with pre-parsed transcript data.
   320→ */
   321→export async function handleCapture(parsed: ParsedTranscript, hookInput: HookInput): Promise<void> {
   322→  const { lastMessage, structured, plainCompletion } = parsed;
   323→
   324→  // Capture work summary (async, non-blocking)
   325→  if (lastMessage) {
   326→    captureWorkSummary(lastMessage, structured).catch(err => {
   327→      console.error('[Capture] History capture failed (non-critical):', err);
   328→    });
   329→  }
   330→
   331→  // Push notifications for long tasks
   332→  const duration = getSessionDurationMinutes();
   333→  if (duration > 0) {
   334→    console.error(`⏱️ Session duration: ${duration.toFixed(1)} minutes`);
   335→  }
   336→
   337→  const hasError = lastMessage && (
   338→    /error|failed|exception|crash/i.test(lastMessage) &&
   339→    /📊\s*STATUS:.*(?:error|failed|broken)/i.test(lastMessage)
   340→  );
   341→
   342→  if (hasError) {
   343→    notifyError(plainCompletion).catch(() => {});
   344→  } else {
   345→    notifyTaskComplete(plainCompletion).catch(() => {});
   346→  }
   347→
   348→  // Observability event
   349→  await sendEventToObservability({
   350→    source_app: getSourceApp(),
   351→    session_id: hookInput.session_id,
   352→    hook_event_type: 'Stop',
   353→    timestamp: getCurrentTimestamp(),
   354→    transcript_path: hookInput.transcript_path,
   355→    summary: structured.completed || plainCompletion,
   356→  }).catch(() => {});
   357→}
