   108→async function getCurrentDate(): Promise<string> {
   109→  try {
   110→    // Cross-platform date formatting using Intl API instead of Unix date command
   111→    const timezone = process.env.TIME_ZONE || 'America/Los_Angeles';
   112→    const now = new Date();
   113→
   114→    const formatter = new Intl.DateTimeFormat('en-US', {
   115→      timeZone: timezone,
   116→      year: 'numeric',
   117→      month: '2-digit',
   118→      day: '2-digit',
   119→      hour: '2-digit',
   120→      minute: '2-digit',
   121→      second: '2-digit',
   122→      timeZoneName: 'short',
   123→      hour12: false
   124→    });
   125→
   126→    // Format: YYYY-MM-DD HH:MM:SS TZ
   127→    const parts = formatter.formatToParts(now);
   128→    const year = parts.find(p => p.type === 'year')?.value || '';
   129→    const month = parts.find(p => p.type === 'month')?.value || '';
   130→    const day = parts.find(p => p.type === 'day')?.value || '';
   131→    const hour = parts.find(p => p.type === 'hour')?.value || '';
   132→    const minute = parts.find(p => p.type === 'minute')?.value || '';
   133→    const second = parts.find(p => p.type === 'second')?.value || '';
   134→    const tzName = parts.find(p => p.type === 'timeZoneName')?.value || '';
   135→
   136→    return `${year}-${month}-${day} ${hour}:${minute}:${second} ${tzName}`;
   137→  } catch (error) {
   138→    console.error('Failed to get current date:', error);
   139→    return new Date().toISOString();
   140→  }
   141→}
