   286→async function checkActiveProgress(paiDir: string): Promise<string | null> {
   287→  const progressDir = join(paiDir, 'MEMORY', 'STATE', 'progress');
   288→
   289→  if (!existsSync(progressDir)) {
   290→    return null;
   291→  }
   292→
   293→  try {
   294→    const files = readdirSync(progressDir).filter(f => f.endsWith('-progress.json'));
   295→
   296→    if (files.length === 0) {
   297→      return null;
   298→    }
   299→
   300→    const activeProjects: ProgressFile[] = [];
   301→
   302→    for (const file of files) {
   303→      try {
   304→        const content = readFileSync(join(progressDir, file), 'utf-8');
   305→        const progress = JSON.parse(content) as ProgressFile;
   306→        if (progress.status === 'active') {
   307→          activeProjects.push(progress);
   308→        }
   309→      } catch (e) {
   310→        // Skip malformed files
   311→      }
   312→    }
   313→
   314→    if (activeProjects.length === 0) {
   315→      return null;
   316→    }
   317→
   318→    // Build summary of active work
   319→    let summary = '\n📋 ACTIVE WORK (from previous sessions):\n';
   320→
   321→    for (const proj of activeProjects) {
   322→      summary += `\n🔵 ${proj.project}\n`;
   323→
   324→      if (proj.objectives && proj.objectives.length > 0) {
   325→        summary += '   Objectives:\n';
   326→        proj.objectives.forEach(o => summary += `   • ${o}\n`);
   327→      }
   328→
   329→      if (proj.handoff_notes) {
   330→        summary += `   Handoff: ${proj.handoff_notes}\n`;
   331→      }
   332→
   333→      if (proj.next_steps && proj.next_steps.length > 0) {
   334→        summary += '   Next steps:\n';
   335→        proj.next_steps.forEach(s => summary += `   → ${s}\n`);
   336→      }
