     1→/**
     2→ * ============================================================================
     3→ * TRACE EMITTER - Theory of Mind Capture System
     4→ * ============================================================================
     5→ *
     6→ * PURPOSE:
     7→ * Captures granular decision traces per-task, enabling retrospective analysis
     8→ * of how THE ALGORITHM made decisions. This is the "theory of mind" layer
     9→ * that allows us to understand and improve the algorithm by looking backwards.
    10→ *
    11→ * INTEGRATION:
    12→ * - All hooks import and use this library to emit events
    13→ * - Events append to Work/[task]/TRACE.jsonl
    14→ * - Nightly synthesis extracts patterns for system-level learning
    15→ *
    16→ * EVENT TYPES:
    17→ * - hook_start/hook_end: Hook lifecycle with duration
    18→ * - ai_call: Any AI model invocation (Haiku classifier, etc.)
    19→ * - decision: Explicit decision point with inputs/outputs
    20→ * - reasoning: Free-form reasoning chain
    21→ * - state_change: Phase transitions, status updates
    22→ * - tool_use: Tool execution summary
    23→ * - failure: Captured failure with context
    24→ * - loopback: Algorithm looped back to earlier phase
    25→ * - user_signal: User feedback (rating, interruption)
    26→ *
    27→ * SAFETY:
    28→ * - Atomic appends with size rotation (1MB per file)
    29→ * - Fail-open design (never blocks on trace errors)
    30→ * - No sensitive data in traces (prompts truncated)
    31→ *
    32→ * ============================================================================
    33→ */
    34→
    35→import { appendFileSync, existsSync, statSync, renameSync, mkdirSync } from 'fs';
    36→import { join, dirname } from 'path';
    37→import { findActiveWorkDir, type AlgorithmPhase } from './work-utils';
    38→import { PLATFORM, IS_WINDOWS } from './platform-paths';
    39→
    40→// DEBUG flag
    41→const DEBUG = process.env.DEBUG_HOOKS === 'true';
    42→
    43→// Maximum size before rotation (1MB)
    44→const MAX_TRACE_SIZE = 1_000_000;
    45→
    46→// Maximum preview length for prompts (avoid leaking full content)
    47→const MAX_PREVIEW_LENGTH = 200;
    48→
    49→/**
    50→ * Trace event types
    51→ */
    52→export type TraceEventType =
    53→  | 'hook_start'      // Hook activation
    54→  | 'hook_end'        // Hook completion
    55→  | 'ai_call'         // Any AI invocation (classifier, summarizer)
    56→  | 'decision'        // Decision point with inputs/outputs
    57→  | 'reasoning'       // Free-form reasoning chain
    58→  | 'state_change'    // Phase transition, status update
    59→  | 'tool_use'        // Tool execution summary
    60→  | 'failure'         // Captured failure with context
    61→  | 'loopback'        // Algorithm looped back to earlier phase
    62→  | 'user_signal';    // User feedback (rating, interruption)
    63→
    64→/**
    65→ * Base trace event structure
    66→ */
    67→export interface TraceEvent {
    68→  ts: string;                    // ISO timestamp with ms precision
    69→  type: TraceEventType;          // Event type
    70→  hook?: string;                 // Hook name if hook-related
    71→  phase?: AlgorithmPhase;        // Current algorithm phase
    72→  data: Record<string, any>;     // Type-specific payload
    73→  duration_ms?: number;          // Execution time if measurable
    74→}
    75→
    76→/**
    77→ * Module-level state for current work directory
    78→ * This is set by hooks at startup and used for all emissions
    79→ */
    80→let currentWorkDir: string | null = null;
    81→
    82→/**
    83→ * Set the active work directory for trace emissions
    84→ * Called at hook startup after finding/creating work item
    85→ */
    86→export function setWorkDir(dir: string): void {
    87→  currentWorkDir = dir;
    88→  if (DEBUG) console.error('[TraceEmitter] Work dir set:', dir);
    89→}
    90→
    91→/**
    92→ * Get the current work directory (auto-detect if not set)
    93→ */
    94→export function getWorkDir(): string | null {
    95→  if (currentWorkDir) return currentWorkDir;
    96→
    97→  // Auto-detect from active work
    98→  const detected = findActiveWorkDir();
    99→  if (detected) {
   100→    currentWorkDir = detected;
   101→    if (DEBUG) console.error('[TraceEmitter] Auto-detected work dir:', detected);
   102→  }
   103→  return currentWorkDir;
   104→}
   105→
   106→/**
   107→ * Get the TRACE.jsonl path for current work directory
   108→ */
   109→function getTracePath(): string | null {
   110→  const workDir = getWorkDir();
   111→  if (!workDir) return null;
   112→  return join(workDir, 'TRACE.jsonl');
   113→}
   114→
   115→/**
   116→ * Rotate trace file if it exceeds size limit
   117→ */
   118→function rotateIfNeeded(tracePath: string): void {
   119→  try {
   120→    if (!existsSync(tracePath)) return;
   121→
   122→    const stats = statSync(tracePath);
   123→    if (stats.size > MAX_TRACE_SIZE) {
   124→      const archivePath = join(
   125→        dirname(tracePath),
   126→        `TRACE-${Date.now()}.jsonl`
   127→      );
   128→      renameSync(tracePath, archivePath);
   129→      if (DEBUG) console.error('[TraceEmitter] Rotated trace to:', archivePath);
   130→    }
   131→  } catch (e) {
   132→    if (DEBUG) console.error('[TraceEmitter] Rotation check failed:', e);
   133→  }
   134→}
   135→
   136→/**
   137→ * Core emit function - appends event to TRACE.jsonl
   138→ * Fail-open design: never throws, never blocks
   139→ *
   140→ * WINDOWS ENHANCEMENT:
   141→ * - Checks path length before writing (Windows MAX_PATH = 260 chars)
   142→ * - Provides helpful error message if path too long
   143→ */
   144→export function emit(event: Omit<TraceEvent, 'ts'>): void {
   145→  const tracePath = getTracePath();
   146→  if (!tracePath) {
   147→    if (DEBUG) console.error('[TraceEmitter] No work dir, skipping emit');
   148→    return;
   149→  }
   150→
   151→  // Windows-specific: Check path length
   152→  if (IS_WINDOWS && tracePath.length > 250) {
   153→    console.error('[TraceEmitter] WARNING: Trace path approaches Windows MAX_PATH limit:');
   154→    console.error(`[TraceEmitter] Path length: ${tracePath.length} characters`);
   155→    console.error(`[TraceEmitter] Limit: 260 characters`);
   156→    console.error(`[TraceEmitter] Path: ${tracePath}`);
   157→    console.error('[TraceEmitter] Consider enabling long path support or using shorter project paths');
   158→  }
   159→
   160→  const fullEvent: TraceEvent = {
   161→    ts: new Date().toISOString(),
   162→    ...event
   163→  };
   164→
   165→  try {
   166→    // Ensure directory exists
   167→    const dir = dirname(tracePath);
   168→    if (!existsSync(dir)) {
   169→      mkdirSync(dir, { recursive: true });
   170→    }
   171→
   172→    // Check for rotation
   173→    rotateIfNeeded(tracePath);
   174→
   175→    // Atomic append
   176→    appendFileSync(tracePath, JSON.stringify(fullEvent) + '\n');
   177→
   178→    if (DEBUG) console.error('[TraceEmitter] Emitted:', event.type, event.hook || '');
   179→  } catch (e) {
   180→    // Fail open - log but don't crash
   181→    if (DEBUG) {
   182→      console.error('[TraceEmitter] Write failed:', e);
   183→
   184→      // Provide Windows-specific troubleshooting
   185→      if (IS_WINDOWS && e.code === 'ENOENT') {
   186→        console.error('[TraceEmitter] Windows troubleshooting:');
   187→        console.error('[TraceEmitter] 1. Check directory exists and is accessible');
   188→        console.error('[TraceEmitter] 2. Check path length (< 260 chars)');
   189→        console.error('[TraceEmitter] 3. Ensure proper permissions');
   190→      }
   191→    }
   192→  }
   193→}
   194→
   195→// ============================================================================
   196→// Convenience Functions for Common Event Types
   197→// ============================================================================
   198→
   199→/**
   200→ * Emit hook_start event
   201→ * Call at the beginning of any hook's main function
   202→ */
   203→export function emitHookStart(
   204→  hookName: string,
   205→  trigger: string,
   206→  data?: Record<string, any>
   207→): void {
   208→  emit({
   209→    type: 'hook_start',
   210→    hook: hookName,
   211→    data: { trigger, ...data }
   212→  });
   213→}
   214→
   215→/**
   216→ * Emit hook_end event
   217→ * Call at the end of any hook's main function (in finally block)
   218→ */
   219→export function emitHookEnd(hookName: string, durationMs: number): void {
   220→  emit({
   221→    type: 'hook_end',
   222→    hook: hookName,
   223→    duration_ms: durationMs,
   224→    data: {}
   225→  });
   226→}
   227→
   228→/**
   229→ * Emit decision event
   230→ * Call at any explicit decision point (classifier output, routing decision)
   231→ */
   232→export function emitDecision(
   233→  hookName: string,
   234→  input: any,
   235→  output: any,
   236→  confidence?: number
   237→): void {
   238→  emit({
   239→    type: 'decision',
   240→    hook: hookName,
   241→    data: {
   242→      input: typeof input === 'string'
   243→        ? input.slice(0, MAX_PREVIEW_LENGTH)
   244→        : input,
   245→      output,
   246→      ...(confidence !== undefined && { confidence })
   247→    }
   248→  });
   249→}
   250→
   251→/**
   252→ * Emit ai_call event
   253→ * Call after any AI model invocation
   254→ */
   255→export function emitAiCall(
   256→  hookName: string,
   257→  model: string,
   258→  tokensIn: number,
   259→  tokensOut: number,
   260→  durationMs: number
   261→): void {
   262→  emit({
   263→    type: 'ai_call',
   264→    hook: hookName,
   265→    data: {
   266→      model,
   267→      tokens_in: tokensIn,
   268→      tokens_out: tokensOut
   269→    },
   270→    duration_ms: durationMs
   271→  });
   272→}
   273→
   274→/**
   275→ * Emit reasoning event
