   330→/**
   331→ * Get Windows-specific environment diagnostic information.
   332→ * Useful for troubleshooting Windows setup issues.
   333→ */
   334→export function getWindowsDiagnostics(): Record<string, string> | null {
   335→  if (!IS_WINDOWS) return null;
   336→
   337→  try {
   338→    return {
   339→      platform: 'Windows',
   340→      platformVersion: process.version,
   341→      arch: process.arch,
   342→      homeDir: HOME_DIR,
   343→      paiDir: PAI_DIR,
   344→      tempDir: TEMP_DIR,
   345→      pathSeparator: PATH_SEPARATOR,
   346→      envUserprofile: process.env.USERPROFILE || 'NOT SET',
   347→      envTemp: process.env.TEMP || 'NOT SET',
   348→      envTmp: process.env.TMP || 'NOT SET',
   349→      envPath: process.env.PATH ? 'SET' : 'NOT SET',
   350→      currentWorkingDirectory: process.cwd(),
   351→      nodeVersion: process.version,
   352→      hasLongPaths: 'Unknown (check registry LongPathsEnabled)'
   353→    };
   354→  } catch (error) {
   355→    return {
   356→      error: `Failed to gather diagnostics: ${error.message}`
   357→    };
   358→  }
   359→}
   360→
   361→/**
   362→ * Log platform information for debugging.
   363→ * Call this function when troubleshooting platform-specific issues.
   364→ */
   365→export function logPlatformInfo(): void {
   366→  const platformName = getPlatformName();
   367→  console.error('\n=== Platform Information ===');
   368→  console.error(`Platform: ${platformName}`);
   369→  console.error(`Node.js: ${process.version}`);
   370→  console.error(`Arch: ${process.arch}`);
   371→  console.error(`Home Directory: ${HOME_DIR}`);
   372→  console.error(`PAI Directory: ${PAI_DIR}`);
   373→  console.error(`Temp Directory: ${TEMP_DIR}`);
   374→  console.error(`Path Separator: "${PATH_SEPARATOR}"`);
   375→
   376→  if (IS_WINDOWS) {
   377→    console.error('\n=== Windows Diagnostics ===');
   378→    const diagnostics = getWindowsDiagnostics();
   379→    if (diagnostics) {
   380→      Object.entries(diagnostics).forEach(([key, value]) => {
   381→        console.error(`${key}: ${value}`);
   382→      });
   383→    }
   384→    console.error('\n=== Windows Setup Tips ===');
   385→    console.error('If experiencing issues:');
   386→    console.error('1. Ensure %USERPROFILE% is set (should be by default)');
   387→    console.error('2. Ensure %TEMP% is set and writable');
   388→    console.error('3. Enable Long Paths in registry if needed:');
   389→    console.error('   - Key: HKLM\\SYSTEM\\CurrentControlSet\\Control\\FileSystem');
   390→    console.error('   - Value: LongPathsEnabled = 1');
   391→    console.error('4. Run PowerShell as Administrator for system operations');
   392→  }
   393→
   394→  console.error('============================\n');
   395→}
